module RefModule (
    input clk,
    input en,
    input reset,
    output reg [2:0] count);
  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt)
begin
    if (reset)
        count <= 3'b000;
    else if (en)
        count <= count + 1;
end
endmodule
